VALUES
  ('bookkeeper-moex-00632', 'bookkeeper', 'bookkeeper-moex-109-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '甲公司總機構設於臺北市，109年8月15日發放股利予股東，下列有關不同類型股東，申報繳納所 得稅方式，何者錯誤？', '["公司發放予境內居住者股東免予扣繳，仍應申報綜合所得稅", "公司發放予非居住者股東應扣繳21%，採就源扣繳不需申報綜合所得稅", "公司發放予境內法人股東免予扣繳，境內法人應併入營利事業所得額", "公司發放予境外法人股東應扣繳21%，採就源扣繳不需申報營利事業所得稅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:23+00:00", "source_pdf_sha1": "771857d89d54", "answer_pdf_sha1": "88c543e15050", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00633', 'bookkeeper', 'bookkeeper-moex-109-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依所得稅法第43條之4規定，依外國法律設立之公司，下列何者為認定實際管理處所在境內之條件？', '["作成重大經營管理、財務管理及人事管理決策之處所在境內", "在境內擁有房地產", "在境內有實 際執行主要經營活動", "財務報表製作或儲存處所在境內  ⑤作成重大經營管理、財務管理及人事管 理決策者為境內居住之個人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:23+00:00", "source_pdf_sha1": "771857d89d54", "answer_pdf_sha1": "88c543e15050", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00634', 'bookkeeper', 'bookkeeper-moex-109-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '甲公司108年度透過私立學校興學基金會指定對Ａ財團法人私立學校捐贈新臺幣250萬元；另直接捐 贈予Ｂ財團法人私立學校運動器材用品價值50萬元。若該公司當年度之營業毛利為1,000萬元，營 業費用（含捐贈費用）800萬元，無營業外收入及損失，請問甲公司申報108年度營利事業所得稅可 認列之捐贈總額為新臺幣多少元？', '["909,090元", "100萬元", "140萬元", "150萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:23+00:00", "source_pdf_sha1": "771857d89d54", "answer_pdf_sha1": "88c543e15050", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00635', 'bookkeeper', 'bookkeeper-moex-109-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '假設甲公司逾期繳納補徵之營利事業所得稅，繳納截止日為6月30日（星期六），該公司於7月6日 繳納，依稅法規定應如何處理？', '["按應納稅額加徵10%滯報金，最低不得少於新臺幣1,500元，最高不得超過新臺幣3萬元", "按當年度營利事業所得稅率計算金額加徵20%怠報金，最低不得少於新臺幣4,500元，最高不得超 過新臺幣9萬元", "按滯納數額加徵1%滯納金", "按滯納數額加徵1%滯納金，另按郵政儲金1年期定存利率按日加計利息"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:23+00:00", "source_pdf_sha1": "771857d89d54", "answer_pdf_sha1": "88c543e15050", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00636', 'bookkeeper', 'bookkeeper-moex-109-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '甲公司之會計年度採曆年制，106年度營利事業所得稅於107年12月完成申報，申報虧損數額300萬 元，依現行所得稅法規定，此筆申報虧損數額可從以後年度純益額中扣除的最後年限為何？', '["111年度", "116年度", "117年度", "不適用盈虧互抵"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:23+00:00", "source_pdf_sha1": "771857d89d54", "answer_pdf_sha1": "88c543e15050", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00637', 'bookkeeper', 'bookkeeper-moex-109-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '甲公司總機構設於我國境內，民國107年以6,500萬元購入房地產，民國108年以6,800萬元出售， 計算土地增值稅之土地漲價總數額為180萬元，應納土地增值稅為36萬元，交易仲介費136萬元， 無其他費用。依所得稅法規定，甲公司該筆交易應如何計入營利事業課稅所得額？', '["以零計入", "虧損16萬元作為營利事業所得額減項", "計入營利事業所得額164萬元", "虧損52萬元作為營利事業所得額減項"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:23+00:00", "source_pdf_sha1": "771857d89d54", "answer_pdf_sha1": "88c543e15050", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00638', 'bookkeeper', 'bookkeeper-moex-109-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依稅捐稽徵法，納稅義務人有溢繳稅額時，其適用退稅相關規定，下列敘述何者正確？', '["因稅捐稽徵機關適用法令錯誤，退稅年限沒有限制，且可加計利息退還", "因納稅義務人自行適用法令錯誤，自繳納之日起5年內提出具體證明，可申請無息退還", "因稅捐稽徵機關適用法令錯誤，退稅沒有年限限制，退稅金額無息退還", "因納稅義務人自行適用法令錯誤，自繳納之日起3年內提出具體證明，加息退還"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:23+00:00", "source_pdf_sha1": "771857d89d54", "answer_pdf_sha1": "88c543e15050", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00639', 'bookkeeper', 'bookkeeper-moex-109-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '下列有關核課期間之敘述，依稅捐稽徵法規定何者錯誤？①在核課期間內，經另發現應徵之稅捐者，', '["對已確定的租稅債權，政府向人民請求履行繳稅之期間", "如地價稅繳 納期間為11月1日至11月30日，其核課期間為12月1日起算5年", "綜合所得稅已於5月15日 誠實申報，其核課期間自5月15日起算5年  ⑤公司營利事業所得稅於5月30日申報但故意逃漏稅 捐者，其核課期間自5月31日起算7年", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:23+00:00", "source_pdf_sha1": "771857d89d54", "answer_pdf_sha1": "88c543e15050", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 22, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00640', 'bookkeeper', 'bookkeeper-moex-109-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依稅捐稽徵法規定，在中華民國境內居住之個人欠繳稅款達一定金額將被限制出境，但已提供相當擔', '["黃金，按九折計算", "上市之 有價證券，按九折計算", "上櫃之有價證券，按八折計算", "易於變價、無產權糾紛且能足額清償之 土地  ⑤銀行存款單摺，按存款本金加計利息計值"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:23+00:00", "source_pdf_sha1": "771857d89d54", "answer_pdf_sha1": "88c543e15050", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-00641', 'bookkeeper', 'bookkeeper-moex-109-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依稅捐稽徵法第5條規定，財政部依互惠原則與外國政府或國際組織商訂稅務用途資訊交換；如果有 關機關、機構未依規定進行金融帳戶盡職審查或其他審查並提供締約他方之資訊，依稅捐稽徵法第46 條之1將由財政部或其授權之機關作何種處罰？', '["新臺幣30萬元以上1千萬元以下罰鍰", "新臺幣20萬元以上1千萬元以下罰鍰", "新臺幣20萬元以上1千萬元以下罰金", "新臺幣30萬元以上1千萬元以下罰金"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:23+00:00", "source_pdf_sha1": "771857d89d54", "answer_pdf_sha1": "88c543e15050", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL)
